import React from 'react';
import { Link } from 'react-router-dom'; // Assure-toi d'importer 'Link'
import "./card.css";

const Card = ({ id, title, cover, alt }) => {
   return (
       <Link to={`/rental/${id}`} className="card-link"> {/* Lien enveloppant toute la carte */}
           <figure className="card">
               <img src={cover} alt={alt} />
               <figcaption>
                   <h2>{title}</h2>
               </figcaption>
           </figure>
       </Link>
   );
};

export default Card;
